#include <stdio.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int A, B;
        scanf("%d %d", &A, &B);
        int needA = 7 - A;
        int needB = 7 - B;
        int ans = needA < needB ? needA : needB;
        printf("%d\n", ans);
    }
    return 0;
}

